def grid(grid: Array[Array[Long]])(x: Long, y: Long, k: Long): Array[Array[Long]] = {
  val m = grid.length
  val n = grid(0).length
  val result = Array.ofDim[Long](m, n)

  for (i <- 0 until m) {
    for (j <- 0 until n) {
      if (i >= x && i < x + k && j >= y && j < y + k) {
        val row = i - x
        val newRow = k - 1 - row
        result(i)(j) = grid(x + newRow)(y + (j - y))
      } else {
        result(i)(j) = grid(i)(j)
      }
    }
  }

  result
}
